            return ['success' => false, 'error' => 'Invalid dimensions'];
        }
        
        $quality = max(1, min(100, intval($quality)));
        
        $inputFilename = uniqid('img_', true) . '.' . $extension;
        $inputPath = $this->uploadDir . $inputFilename;
        
        if (!move_uploaded_file($file['tmp_name'], $inputPath)) {
